SELECT ?console ?cpu ?storage ?memory ?graphics ?backward WHERE {
  ?console wdt:P31 wd:Q104247;  # instance of video game console
         wdt:P4815 wd:Q22771.   # ninth generation

  OPTIONAL { ?console wdt:P783 ?cpu. }
  OPTIONAL { ?console wdt:P515 ?storage. }
  OPTIONAL { ?console wdt:P2001 ?memory. }
  OPTIONAL { ?console wdt:P333 ?graphics. }
  OPTIONAL { ?console wdt:P2658 ?backward. }
}

SELECT DISTINCT ?console ?consoleLabel ?cpu ?storage ?memory ?graphics ?backward WHERE {
  ?console wdt:P31 wd:Q104247;  # instance of video game console
         wdt:P4815 wd:Q22771.   # ninth generation

  OPTIONAL { ?console wdt:P1759 ?cpu. }
  OPTIONAL { ?console wdt:P515 ?storage. }
  OPTIONAL { ?console wdt:P2001 ?memory. }
  OPTIONAL { ?console wdt:P333 ?graphics. }
  OPTIONAL { ?console wdt:P2658 ?backward. }
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

SELECT ?console ?consoleLabel ?cpu ?cpuLabel ?storage ?memory ?graphics ?graphicsLabel ?backward ?backwardLabel
WHERE {
  ?console wdt:P31 wd:Q104247;  # instance of video game console
         wdt:P4815 wd:Q22771.   # ninth generation

  OPTIONAL { ?console wdt:P5070 ?cpu. }
  OPTIONAL { ?console wdt:P2048 ?storage. }
  OPTIONAL { ?console wdt:P2001 ?memory. }
  OPTIONAL { ?console wdt:P4591 ?graphics. }
  OPTIONAL { ?console wdt:P2658 ?backward. }

  ?console rdfs:label ?consoleLabel FILTER (lang(?consoleLabel) = "en").
  OPTIONAL { ?cpu rdfs:label ?cpuLabel FILTER (lang(?cpuLabel) = "en"). }
  OPTIONAL { ?graphics rdfs:label ?graphicsLabel FILTER (lang(?graphicsLabel) = "en"). }
  OPTIONAL { ?backward rdfs:label ?backwardLabel FILTER (lang(?backwardLabel) = "en"). }
}

