SELECT DISTINCT ?console ?consoleLabel ?cpuLabel ?storageOutput ?memoryOutput ?graphicsLabel ?backwardLabel
WHERE {
  ?console wdt:P31 wd:Q104247;  # instance of video game console
         wdt:P4815 wd:Q105215255;  # ninth generation
         rdfs:label ?consoleLabel FILTER (lang(?consoleLabel) = "en").

  OPTIONAL {
    ?console wdt:P783 ?cpu.
    ?cpu rdfs:label ?cpuLabel FILTER (lang(?cpuLabel) = "en").
  }
  OPTIONAL {
    ?console p:P2048/psv:P2048 ?storageNode.
    ?storageNode wikibase:quantityValue ?storageValue.
    ?storageNode wikibase:quantityUnit ?storageUnit.
    ?storageUnit rdfs:label ?storageUnitLabel FILTER (lang(?storageUnitLabel) = "en").
    BIND(CONCAT(STR(?storageValue), " ", ?storageUnitLabel) AS ?storageOutput)
  }
  OPTIONAL {
    ?console p:P2001/psv:P2001 ?memoryNode.
    ?memoryNode wikibase:quantityValue ?memoryValue.
    ?memoryNode wikibase:quantityUnit ?memoryUnit.
    ?memoryUnit rdfs:label ?memoryUnitLabel FILTER (lang(?memoryUnitLabel) = "en").
    BIND(CONCAT(STR(?memoryValue), " ", ?memoryUnitLabel) AS ?memoryOutput)
  }
  OPTIONAL {
    ?console wdt:P4591 ?graphics.
    ?graphics rdfs:label ?graphicsLabel FILTER (lang(?graphicsLabel) = "en").
  }
  OPTIONAL {
    ?console wdt:P2658 ?backward.
    ?backward rdfs:label ?backwardLabel FILTER (lang(?backwardLabel) = "en").
  }
}
LIMIT 10

